11114 /// Calculate the scalar and the vector costs from vectorizing set of GEPs.
11115 static std::pair<InstructionCost, InstructionCost>
11116 getGEPCosts(const TargetTransformInfo &TTI, ArrayRef<Value *> Ptrs,
11117             Value *BasePtr, unsigned Opcode, TTI::TargetCostKind CostKind,
11118             Type *ScalarTy, VectorType *VecTy) {
11119   InstructionCost ScalarCost = 0;
11120   InstructionCost VecCost = 0;
11121   // Here we differentiate two cases: (1) when Ptrs represent a regular
11122   // vectorization tree node (as they are pointer arguments of scattered
11123   // loads) or (2) when Ptrs are the arguments of loads or stores being
11124   // vectorized as plane wide unit-stride load/store since all the
11125   // loads/stores are known to be from/to adjacent locations.
11126   if (Opcode == Instruction::Load || Opcode == Instruction::Store) {
11127     // Case 2: estimate costs for pointer related costs when vectorizing to
11128     // a wide load/store.
11129     // Scalar cost is estimated as a set of pointers with known relationship
11130     // between them.
11131     // For vector code we will use BasePtr as argument for the wide load/store
11132     // but we also need to account all the instructions which are going to
11133     // stay in vectorized code due to uses outside of these scalar
11134     // loads/stores.
11135     ScalarCost = TTI.getPointersChainCost(
11136         Ptrs, BasePtr, TTI::PointersChainInfo::getUnitStride(), ScalarTy,
11137         CostKind);
11138 
11139     SmallVector<const Value *> PtrsRetainedInVecCode;
11140     for (Value *V : Ptrs) {
11141       if (V == BasePtr) {
11142         PtrsRetainedInVecCode.push_back(V);
11143         continue;
11144       }
11145       auto *Ptr = dyn_cast<GetElementPtrInst>(V);
11146       // For simplicity assume Ptr to stay in vectorized code if it's not a
11147       // GEP instruction. We don't care since it's cost considered free.
11148       // TODO: We should check for any uses outside of vectorizable tree
11149       // rather than just single use.
11150       if (!Ptr || !Ptr->hasOneUse())
11151         PtrsRetainedInVecCode.push_back(V);
11152     }
11153 
11154     if (PtrsRetainedInVecCode.size() == Ptrs.size()) {
11155       // If all pointers stay in vectorized code then we don't have
11156       // any savings on that.
11157       return std::make_pair(TTI::TCC_Free, TTI::TCC_Free);
11158     }
11159     VecCost = TTI.getPointersChainCost(PtrsRetainedInVecCode, BasePtr,
11160                                        TTI::PointersChainInfo::getKnownStride(),
11161                                        VecTy, CostKind);
11162   } else {
11163     // Case 1: Ptrs are the arguments of loads that we are going to transform
11164     // into masked gather load intrinsic.
11165     // All the scalar GEPs will be removed as a result of vectorization.
11166     // For any external uses of some lanes extract element instructions will
11167     // be generated (which cost is estimated separately).
11168     TTI::PointersChainInfo PtrsInfo =
11169         all_of(Ptrs,
11170                [](const Value *V) {
11171                  auto *Ptr = dyn_cast<GetElementPtrInst>(V);
11172                  return Ptr && !Ptr->hasAllConstantIndices();
11173                })
11174             ? TTI::PointersChainInfo::getUnknownStride()
11175             : TTI::PointersChainInfo::getKnownStride();
11176 
11177     ScalarCost =
11178         TTI.getPointersChainCost(Ptrs, BasePtr, PtrsInfo, ScalarTy, CostKind);
11179     auto *BaseGEP = dyn_cast<GEPOperator>(BasePtr);
11180     if (!BaseGEP) {
11181       auto *It = find_if(Ptrs, IsaPred<GEPOperator>);
11182       if (It != Ptrs.end())
11183         BaseGEP = cast<GEPOperator>(*It);
11184     }
11185     if (BaseGEP) {
11186       SmallVector<const Value *> Indices(BaseGEP->indices());
11187       VecCost = TTI.getGEPCost(BaseGEP->getSourceElementType(),
11188                                BaseGEP->getPointerOperand(), Indices, VecTy,
11189                                CostKind);
11190     }
11191   }
11192 
11193   return std::make_pair(ScalarCost, VecCost);
11194 }
